import { 運筆 } from '../bi.js';
import { 手勢, 指寬 } from './zhi.js';
// 握拳橫：拳背向前橫執一軸（杵）；心 (x,z)，軸自拳中過
export function 握拳橫(bi, x, z, 比 = 1, 輕 = false) {
    const { M, Qk, C, S, 骨, 衣, 細 } = 運筆(bi);
    const X = (dx) => x + dx * 比, Z = (dz) => z + dz * 比;
    const 郭 = 輕 ? 衣 : 骨;
    // 拳郭：閉而圓
    郭(() => {
        M(X(-1.45), Z(-1.15));
        C(X(-1.75), Z(-0.1), X(-1.6), Z(0.9), X(-0.8), Z(1.35));
        C(X(0.2), Z(1.85), X(1.35), Z(1.55), X(1.75), Z(0.8));
        C(X(2.1), Z(0.0), X(1.95), Z(-1.0), X(1.4), Z(-1.45));
        C(X(0.5), Z(-2.1), X(-0.9), Z(-1.95), X(-1.45), Z(-1.15));
        S();
    });
    衣(() => {
        // 指根之脊：拳上一弧
        M(X(-1.1), Z(-1.3));
        Qk(X(0.3), Z(-1.7), X(1.3), Z(-1.15));
        S();
        // 指縫：一道（多則亂郭）
        細(() => { M(X(0.35), Z(-1.45)); Qk(X(0.48), Z(-0.45), X(0.36), Z(0.65)); S(); });
        // 拇指：自左緣抱軸而上
        M(X(-1.5), Z(0.1));
        Qk(X(-0.9), Z(-0.55), X(-0.1), Z(-0.7));
        S();
    });
}
// 握拳覆：自上覆執一豎柄（鈴）；心 (x,z)＝拳心，柄自拳下出
export function 握拳覆(bi, x, z, 比 = 1, 輕 = false) {
    const { M, Qk, C, S, 骨, 衣, 細 } = 運筆(bi);
    const X = (dx) => x + dx * 比, Z = (dz) => z + dz * 比;
    const 郭 = 輕 ? 衣 : 骨;
    // 拳郭：覆掌之丘
    郭(() => {
        M(X(-1.7), Z(0.35));
        C(X(-1.75), Z(-0.6), X(-1.0), Z(-1.3), X(0.05), Z(-1.3));
        C(X(1.1), Z(-1.3), X(1.85), Z(-0.6), X(1.8), Z(0.4));
        Qk(X(1.7), Z(1.1), X(1.1), Z(1.3));
        S();
        M(X(1.1), Z(1.3));
        Qk(X(0), Z(1.55), X(-1.15), Z(1.25));
        Qk(X(-1.65), Z(1.0), X(-1.7), Z(0.35));
        S();
    });
    衣(() => {
        // 指節之列：覆掌前緣四拱
        for (const fx of [-1.05, -0.35, 0.35, 1.05])
            bi.A(X(fx), Z(1.05), 0.34 * 比, Math.PI * 1.05, Math.PI * 0.05);
        // 拇指：側抱柄
        M(X(-1.6), Z(0.5));
        Qk(X(-1.0), Z(1.15), X(-0.25), Z(1.3));
        S();
    });
}
// 側拳：側觀之拳（承四佛腹前握拳之形，2026-07-06 掛旋鏡蔽法為部件）——
// 郭圓渾成丘、指背三稜、拇指橫抱；θ＝旋（+a 軸向腕側前臂），鏡＝-1 左右互換。
// 先蔽後勒：掛臂即斷底線（條帛・軀幹線沒於拳後——線描無遮擋之律）。
export function 側拳(bi, x, z, θ = 0, 比 = 1, 鏡 = 1) {
    const { M, Qk, C, S, 衣, 細 } = 運筆(bi);
    const cos = Math.cos(θ), sin = Math.sin(θ);
    const P = (a, b) => [x + (a * 鏡 * cos - b * sin) * 比, z + (a * 鏡 * sin + b * cos) * 比];
    // 蔽：拳丘之塊（郭之內縮多邊形）
    {
        const { ctx, u, Y } = bi;
        const 郭點 = [[-1.5, -1.25], [-2.3, -0.55], [-2.45, 0.3], [-1.8, 1.05],
            [-1.0, 1.95], [0.7, 2.15], [1.5, 1.35], [2.25, 0.55], [2.1, -0.75], [1.2, -1.25], [-0.1, -1.75]];
        ctx.save();
        ctx.globalCompositeOperation = 'destination-out';
        ctx.beginPath();
        郭點.forEach(([a, b], i) => {
            const [px, pz] = P(a, b);
            if (i)
                ctx.lineTo(px * u, Y(pz));
            else
                ctx.moveTo(px * u, Y(pz));
        });
        ctx.closePath();
        ctx.fill();
        ctx.restore();
    }
    const 至M = (a, b) => { const [px, pz] = P(a, b); M(px, pz); };
    const 至Q = (ca, cb, a, b) => {
        const [cx, cz] = P(ca, cb), [px, pz] = P(a, b);
        Qk(cx, cz, px, pz);
    };
    const 至C = (c1a, c1b, c2a, c2b, a, b) => {
        const [x1, z1] = P(c1a, c1b), [x2, z2] = P(c2a, c2b), [px, pz] = P(a, b);
        C(x1, z1, x2, z2, px, pz);
    };
    衣(() => {
        // 拳郭：閉而圓（弧不露稜）
        至M(-1.5, -1.25);
        至C(-2.25, -0.75, -2.45, 0.25, -1.8, 1.05);
        至C(-1.0, 1.95, 0.7, 2.15, 1.5, 1.35);
        至C(2.25, 0.55, 2.1, -0.75, 1.2, -1.25);
        至Q(-0.1, -1.8, -1.5, -1.25);
        S();
        細(() => {
            // 指背三稜
            for (const t of [0, 1, 2]) {
                至M(-1.6 + t * 0.95, -1.2 + t * 0.12);
                至Q(-1.85 + t * 0.95, -0.45 + t * 0.15, -1.45 + t * 0.95, 0.35 + t * 0.18);
                S();
            }
            // 拇指橫抱
            至M(-1.2, 1.35);
            至Q(-0.2, 1.7, 0.8, 1.5);
            S();
        });
    });
}
// 執杵手：右手橫執杵軸（軸傾 θ），拳背向觀者——四指裹軸逐見其節，
// 拇指反扣軸下，指梢與拇指尖相就（飛天之柔：指帶微弧不僵直）
export function 執杵手(bi, x, z, θ = 0, 比 = 1) {
    const { M, Qk, C, S, 骨, 衣, 細, 逸 } = 運筆(bi);
    const cos = Math.cos(θ), sin = Math.sin(θ);
    const P = (a, b) => [x + (a * cos - b * sin) * 比, z + (a * sin + b * cos) * 比];
    const 至M = (a, b) => { const [px, pz] = P(a, b); M(px, pz); };
    const 至Q = (ca, cb, a, b) => {
        const [cx, cz] = P(ca, cb), [px, pz] = P(a, b);
        Qk(cx, cz, px, pz);
    };
    const 至C = (c1a, c1b, c2a, c2b, a, b) => {
        const [x1, z1] = P(c1a, c1b), [x2, z2] = P(c2a, c2b), [px, pz] = P(a, b);
        C(x1, z1, x2, z2, px, pz);
    };
    // 掌背：自腕至指根之脊（骨線立形）
    骨(() => {
        至M(-2.75, -0.85);
        至Q(-2.0, -1.55, -1.15, -1.62);
        S(); // 腕上緣→指根脊起
        至M(-2.8, 0.35);
        至Q(-2.55, 0.9, -2.15, 1.05);
        S(); // 腕下緣→拇指根
    });
    衣(() => {
        // 線描畫其可見：四指裹於軸後乃隱，所見者掌背之丘、指根之脊、
        // 軸下微露之四梢、橫過之拇指——解剖知其隱而不畫其隱
        // 指根之脊：橫貫掌背前緣
        至M(-1.15, -1.62);
        至Q(0.15, -1.85, 1.42, -1.55);
        S();
        // 掌背右緣：脊末收向軸
        至M(1.42, -1.55);
        至Q(1.62, -1.1, 1.55, -0.55);
        S();
        // 四梢：軸下微露（各一小弧，梢向掌心回）
        逸(() => {
            for (const t of [0, 1, 2, 3]) {
                const a0 = 1.15 - t * 0.62;
                至M(a0 + 0.22, 0.72);
                至Q(a0 + 0.1, 1.18 - t * 0.03, a0 - 0.22, 1.28 - t * 0.05);
                S();
            }
            // 拇指：自根沿軸下橫過，與食指梢相就
            至M(-2.15, 1.05);
            至C(-1.45, 1.52, -0.6, 1.6, 0.05, 1.34);
            S();
        });
        // 腕節一線
        細(() => { 至M(-2.95, -0.5); 至Q(-3.15, 0.0, -3.0, 0.5); S(); });
    });
}
// 執鈴手：左手自上覆執柄——指之機重鑄（2026-07-05 歸一波）：掌背之杆一貫入
// 頭指之根（氣韻連貫之律），四指逐節裹柄（蔽鑿使柄線斷於指），拇指內傍。
export function 執鈴手(bi, x, z, 比 = 1) {
    const { M, Qk, S, 骨, 細 } = 運筆(bi);
    const s = 手勢(bi, x, z, 比);
    // 掌之蔽：柄與鈴肩之線斷於掌下
    const 丘 = [];
    for (let i = 0; i < 10; i++) {
        const φ = (i / 10) * Math.PI * 2;
        丘.push([Math.cos(φ) * 1.95, -0.15 + Math.sin(φ) * 1.5]);
    }
    s.蔽(丘);
    // 掌背之丘：自腕一杆隆起，末勢正入頭指之根（骨線）
    骨(() => {
        M(x - 1.55 * 比, z - 0.85 * 比);
        Qk(x - 1.0 * 比, z - 1.35 * 比, x - 0.35 * 比, z - 1.45 * 比);
        S();
        M(x - 0.35 * 比, z - 1.45 * 比);
        Qk(x + 0.85 * 比, z - 1.55 * 比, x + 1.62 * 比, z - 0.95 * 比);
        S();
    });
    // 四指：自脊而降，逐節裹柄（後小前頭，梢向柄心微曲）
    s.衣(() => {
        const 目 = [
            [-1.05, -0.75, 0.10, [1.35, 1.0], 指寬.小根, 指寬.小梢],
            [-0.3, -1.05, 0.06, [1.5, 1.15], 指寬.根, 指寬.梢],
            [0.5, -1.15, 0.02, [1.55, 1.2], 指寬.根, 指寬.梢],
            [1.3, -1.0, -0.04, [1.45, 1.1], 0.92, 0.70],
        ];
        for (const [根a, 根b, 斜, 長, w0, w1] of 目) {
            const 鏈 = s.指(根a, 根b, Math.PI / 2 + 斜, 長, [0, 0.3]);
            s.畫(鏈, w0, w1, { 紋: true, 甲: Math.abs(比) >= 2 });
        }
        // 拇指：自腕側內傍柄，一杆而抵
        const 拇 = s.指(-1.62, -0.55, Math.PI / 2 - 0.42, [1.35, 1.05], [0, 0.35]);
        s.畫(拇, 指寬.拇根, 指寬.拇梢, { 紋: true, 甲: Math.abs(比) >= 2 });
    });
    // 腕節：一紋承臂（掌臂相接之杆）
    細(() => { M(x - 1.7 * 比, z - 1.15 * 比); Qk(x - 1.1 * 比, z - 1.6 * 比, x - 0.4 * 比, z - 1.62 * 比); S(); });
}
